using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ILogger<TicketClassifierService> _logger;

    // Label names ordered to match the Score array after key-to-value mapping
    public string[] LabelNames { get; }
    public Dictionary<string, double> EvaluationMetrics { get; }

    public TicketClassifierService(ILogger<TicketClassifierService> logger)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainModel(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract label names in the order ML.NET assigns them internally
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Label"]
            .GetKeyValues(ref labelBuffer);
        LabelNames = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        EvaluationMetrics = EvaluateModel(dataView);
    }

    private ITransformer TrainModel(IDataView dataView)
    {
        // Combine Subject + Description into a single text feature, then featurize
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(dataView);
        _logger.LogInformation("Model training complete.");

        return model;
    }

    private Dictionary<string, double> EvaluateModel(IDataView dataView)
    {
        // With a small dataset, evaluate on the training data to report baseline metrics
        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var result = new Dictionary<string, double>
        {
            ["MacroAccuracy"] = metrics.MacroAccuracy,
            ["MicroAccuracy"] = metrics.MicroAccuracy,
            ["LogLoss"] = metrics.LogLoss,
            ["LogLossReduction"] = metrics.LogLossReduction
        };

        _logger.LogInformation("Model evaluation — MacroAccuracy: {MacroAccuracy:P2}, MicroAccuracy: {MicroAccuracy:P2}",
            metrics.MacroAccuracy, metrics.MicroAccuracy);

        return result;
    }

    public TicketClassificationResult Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < LabelNames.Length; i++)
        {
            confidence[LabelNames[i]] = prediction.Score[i];
        }

        return new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predict the category of a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        var result = _classifier.Predict(request);
        return Ok(result);
    }

    /// <summary>
    /// Return model evaluation metrics computed at startup.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<Dictionary<string, double>> GetMetrics()
    {
        return Ok(_classifier.EvaluationMetrics);
    }
}

